/**
 * Implementation note: Since standard JavaScript environments do not include a built-in Priority Queue,
 * a minimal implementation of a MinHeap is included to ensure the time complexity of Dijkstra's algorithm
 * remains $O(E \log V)$, leading to an overall acceptable $O(N \cdot M \log N)$ solution for APSP.
 * Costs are kept as standard JavaScript Numbers, which safely handle up to 2^53 - 1 (approx 9e15),
 * sufficient for the maximum possible total cost (around 10^14).
 */

// Helper class for MinPriorityQueue
class MinPriorityQueue {
    constructor() {
        // Stores [distance, node]
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    size() {
        return this.heap.length;
    }

    peek() {
        return this.heap[0];
    }

    // Helper functions for heap indexing
    getParentIndex(i) { return Math.floor((i - 1) / 2); }
    getLeftChildIndex(i) { return 2 * i + 1; }
    getRightChildIndex(i) { return 2 * i + 2; }

    swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    // Bubble up operation
    bubbleUp(index) {
        let currentIndex = index;
        let parentIndex = this.getParentIndex(currentIndex);

        while (currentIndex > 0 && this.heap[currentIndex][0] < this.heap[parentIndex][0]) {
            this.swap(currentIndex, parentIndex);
            currentIndex = parentIndex;
            parentIndex = this.getParentIndex(currentIndex);
        }
    }

    // Sink down operation
    bubbleDown(index) {
        let currentIndex = index;
        const lastIndex = this.heap.length - 1;

        while (true) {
            let leftIndex = this.getLeftChildIndex(currentIndex);
            let rightIndex = this.getRightChildIndex(currentIndex);
            let smallest = currentIndex;

            // Compare with left child
            if (leftIndex <= lastIndex && this.heap[leftIndex][0] < this.heap[smallest][0]) {
                smallest = leftIndex;
            }

            // Compare with right child
            if (rightIndex <= lastIndex && this.heap[rightIndex][0] < this.heap[smallest][0]) {
                smallest = rightIndex;
            }

            if (smallest !== currentIndex) {
                this.swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }

    enqueue(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return min;
    }
}

function solve(n, prices, roads) {
    // Step 1: Build adjacency lists for the two scenarios

    // G_empty: Edge weight is 'cost'
    const adjEmpty = Array(n).fill(0).map(() => []);

    // G_carry: Edge weight is 'cost * tax'
    const adjCarry = Array(n).fill(0).map(() => []);

    for (const [u, v, cost, tax] of roads) {
        const costEmpty = cost;
        const costCarry = cost * tax;

        // Roads are bidirectional

        // Graph Empty
        adjEmpty[u].push({ neighbor: v, weight: costEmpty });
        adjEmpty[v].push({ neighbor: u, weight: costEmpty });

        // Graph Carry
        adjCarry[u].push({ neighbor: v, weight: costCarry });
        adjCarry[v].push({ neighbor: u, weight: costCarry });
    }

    // Step 2: Implement Dijkstra's algorithm
    const INF = Infinity;

    /**
     * Runs Dijkstra's algorithm starting from a source node on a given adjacency list.
     * @param {number} startNode - The source node.
     * @param {Array<Array<{neighbor: number, weight: number}>>} adj - The adjacency list.
     * @returns {Array<number>} Array of shortest distances from startNode to all other nodes.
     */
    function dijkstra(startNode, adj) {
        const distances = Array(n).fill(INF);
        distances[startNode] = 0;

        // Priority Queue stores [distance, node]
        const pq = new MinPriorityQueue();
        pq.enqueue([0, startNode]);

        while (!pq.isEmpty()) {
            const [d, u] = pq.dequeue();

            if (d > distances[u]) {
                continue;
            }

            for (const edge of adj[u]) {
                const v = edge.neighbor;
                const weight = edge.weight;

                if (distances[u] + weight < distances[v]) {
                    distances[v] = distances[u] + weight;
                    pq.enqueue([distances[v], v]);
                }
            }
        }
        return distances;
    }

    // Step 3: Compute All-Pairs Shortest Paths (APSP)

    // Distances from k to j using empty hand travel
    const DistEmpty = []; 
    for (let k = 0; k < n; k++) {
        DistEmpty.push(dijkstra(k, adjEmpty));
    }

    // Distances from k to j using carrying apples travel
    const DistCarry = [];
    for (let k = 0; k < n; k++) {
        DistCarry.push(dijkstra(k, adjCarry));
    }

    // Step 4: Calculate the final answer ans[i]
    const ans = Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at store i
        let minCost = prices[i];

        // Option 2: Travel to store j, buy, and travel back to i
        for (let j = 0; j < n; j++) {
            // Cost = Travel(i -> j, empty) + prices[j] + Travel(j -> i, carry)

            const costEmpty_i_to_j = DistEmpty[i][j];
            const costCarry_j_to_i = DistCarry[j][i];

            // If either path is unreachable, skip
            if (costEmpty_i_to_j === INF || costCarry_j_to_i === INF) {
                continue;
            }

            const totalCost = costEmpty_i_to_j + prices[j] + costCarry_j_to_i;

            if (totalCost < minCost) {
                minCost = totalCost;
            }
        }

        ans[i] = minCost;
    }

    return ans;
}

